const items = $input.all();

let parsed = [];
try {
  const raw = items[0].json;
  // /api/generate returns { response: "..." } where response is the JSON string
  // format:json may also return fields directly in raw
  let jsonString = raw.response || raw.text || raw.content || '';

  if (jsonString) {
    jsonString = jsonString
      .replace(/```(?:json)?\s*/g, '')
      .replace(/\s*```/g, '')
      .trim();
    parsed = JSON.parse(jsonString);
  } else if (raw.fullName || raw.name) {
    parsed = [raw];
  } else {
    const str = JSON.stringify(raw);
    parsed = JSON.parse(str);
  }
} catch(e) {
  console.log('Parse Fehler:', e.message);
  return [];
}

if (!Array.isArray(parsed)) {
  parsed = [parsed];
}

// Deep search helpers
function findInObj(obj, keys) {
  if (!obj || typeof obj !== 'object') return '';
  for (const key of keys) {
    if (obj[key] && typeof obj[key] === 'string') return obj[key];
  }
  for (const val of Object.values(obj)) {
    if (typeof val === 'object') {
      const found = findInObj(val, keys);
      if (found) return found;
    }
    if (Array.isArray(val)) {
      for (const item of val) {
        const found = findInObj(item, keys);
        if (found) return found;
      }
    }
  }
  return '';
}

function findEmail(obj) {
  const str = JSON.stringify(obj);
  const match = str.match(/"([^"]+@[^"]+\.[^"]+)"/);
  return match ? match[1] : '';
}

function findPhones(obj) {
  const str = JSON.stringify(obj);
  const matches = [...str.matchAll(/"(\+?(?:49|0)[\d\s\/()\\-]{6,20})"/g)];
  return matches.map(m => m[1].trim());
}

const contacts = parsed.map(obj => {
  const fullName = findInObj(obj, ['fullName', 'name', 'full_name']) ||
    (Array.isArray(obj.references) ? obj.references[0] : '') || '';
  const email = findInObj(obj, ['email', 'mail', 'e-mail']) || findEmail(obj);
  const validEmail = email.includes('@') ? email : '';

  const phones = findPhones(obj);
  let mobilePhone = findInObj(obj, ['mobilePhone', 'mobile', 'mobil', 'handy']) || '';
  let landlinePhone = findInObj(obj, ['landlinePhone', 'landline', 'phone', 'tel', 'telefon', 'festnetz', 'büro', 'office']) || '';

  if (!mobilePhone && !landlinePhone) {
    for (const p of phones) {
      if (isMobile(p) && !mobilePhone) mobilePhone = p;
      else if (!isMobile(p) && !landlinePhone) landlinePhone = p;
    }
  }

  return { fullName, mobilePhone, landlinePhone, email: validEmail };
});

// Validate: phone or email must appear literally in the original email text
const sourceText = $('Prepare Ollama Request').first().json.sourceText || '';
const sourceDigits = sourceText.replace(/\D/g, '');
const sourceLower = sourceText.toLowerCase();

function phoneInSource(phone) {
  if (!phone) return false;
  const digits = phone.replace(/\D/g, '');
  if (digits.length < 8) return false;
  return sourceDigits.includes(digits.slice(-10)) || sourceDigits.includes(digits.slice(-8));
}

function emailInSource(email) {
  if (!email || !email.includes('@')) return false;
  return sourceLower.includes(email.toLowerCase());
}

const verified = contacts.filter(c =>
  phoneInSource(c.mobilePhone) || phoneInSource(c.landlinePhone) || emailInSource(c.email)
);

return verified.map(contact => ({
  json: {
    line: `${contact.fullName || ''}\t${contact.mobilePhone || ''}\t${contact.landlinePhone || ''}\t${contact.email || ''}`
  }
}));

const items = $input.all();
const plainText = items.map(item => item.json.line).join('\n');

return [{
  json: {
    text: plainText
  }
}];

const items = $input.all();
const existingContent = items[0].json.existingContent || '';
const newContactsText = items[0].json.text || '';

function normalizePhone(phone) {
  if (!phone) return '';
  return phone.replace(/[\s()\-\/]/g, '');
}

function padRight(str, len) {
  if (!str) str = '';
  return str.length >= len ? str : str + ' '.repeat(len - str.length);
}

// Detect column widths from the separator row (e.g. |---|---|)
let colWidths = [30, 17, 18, 37];
const sepLine = existingContent.split('\n').find(l => /^\|[-|]+\|$/.test(l.trim()));
if (sepLine) {
  const segments = sepLine.split('|').filter((_, i, arr) => i > 0 && i < arr.length - 1);
  if (segments.length >= 4) {
    colWidths = segments.map(s => Math.max(s.length - 2, 1));
  }
}

function formatRow(c) {
  return `| ${padRight(c.fullName, colWidths[0])} | ${padRight(c.mobilePhone, colWidths[1])} | ${padRight(c.landlinePhone, colWidths[2])} | ${padRight(c.email, colWidths[3])} |`;
}

const newLines = newContactsText.split('\n').filter(l => l.trim());
const newContacts = newLines.map(line => {
  const parts = line.split('	').map(p => p.trim());
  return {
    fullName: parts[0] || '',
    mobilePhone: normalizePhone(parts[1]),
    landlinePhone: normalizePhone(parts[2]),
    email: parts[3] || ''
  };
});

const companyKeywords = ['team', 'gmbh', 'recruiting', 'service', 'inc', 'ltd', ' ag', 'ug ', ' kg', 'ohg', 'gbr'];

function isCompanyContact(name) {
  const lower = name.toLowerCase();
  return companyKeywords.some(kw => lower.includes(kw));
}

function isMobile(phone) {
  const n = phone.replace(/[\s()\-\/]/g, '');
  return /^(\+49|0049)(15|16|17)/.test(n) || /^0(15|16|17)/.test(n);
}

const filtered = newContacts.filter(c => {
  if (!c.fullName) return false;
  const nameLower = c.fullName.toLowerCase();
  if (nameLower.includes('alexandrov') || nameLower === 'atanas alexandrov') return false;
  if (!c.mobilePhone && !c.landlinePhone) return false;
  if (isCompanyContact(c.fullName)) return false;
  return true;
}).map(c => {
  // Re-classify phones in case model assigned them incorrectly
  let { mobilePhone, landlinePhone } = c;
  if (mobilePhone && !isMobile(mobilePhone)) {
    if (!landlinePhone) landlinePhone = mobilePhone;
    mobilePhone = '';
  }
  if (landlinePhone && isMobile(landlinePhone)) {
    if (!mobilePhone) mobilePhone = landlinePhone;
    landlinePhone = '';
  }
  return { ...c, mobilePhone, landlinePhone };
});

// Parse existing table rows
function parseTableRow(line) {
  if (!line.startsWith('|') || line.startsWith('|---') || line.startsWith('| Name') || line.startsWith('| ---')) return null;
  const cols = line.split('|').map(c => c.trim());
  if (cols.length < 5) return null;
  return { name: cols[1], mobile: cols[2], landline: cols[3], email: cols[4] };
}

let lines = existingContent.split('\n');
let changed = false;

const toAppend = [];

for (const c of filtered) {
  const nameLower = c.fullName.toLowerCase();
  let found = false;

  for (let i = 0; i < lines.length; i++) {
    const row = parseTableRow(lines[i]);
    if (row && row.name.toLowerCase() === nameLower) {
      found = true;
      const mobileChanged = c.mobilePhone && row.mobile !== c.mobilePhone;
      const landlineChanged = c.landlinePhone && row.landline !== c.landlinePhone;
      const emailChanged = c.email && row.email !== c.email;
      if (mobileChanged || landlineChanged || emailChanged) {
        lines[i] = formatRow({
          fullName: row.name,
          mobilePhone: c.mobilePhone || row.mobile,
          landlinePhone: c.landlinePhone || row.landline,
          email: c.email || row.email
        });
        changed = true;
      }
      break;
    }
  }

  if (!found) {
    toAppend.push(c);
  }
}

let result = lines.join('\n');

if (toAppend.length > 0) {
  const newRows = toAppend.map(c => formatRow(c));
  result = result.trimEnd() + '\n' + newRows.join('\n');
}

if (!changed && toAppend.length === 0) {
  return [{ json: { text: existingContent.trimEnd() + '\n' } }];
}

return [{ json: { text: result.trimEnd() + '\n' } }];

